+ * Setup Service - Manages toolchain readiness and installation.
+ *
+ * Provides detection, installation, and verification of
+ * agent CLIs and developer tools for the Flywheel Gateway setup wizard.
+ */
+
+import { getCorrelationId, getLogger } from "../middleware/correlation";
+import {
+  type DetectedCLI,
+  type DetectionResult,
+  type DetectedType,
+  getAgentDetectionService,
+} from "./agent-detection.service";
+import { getHub } from "../ws/hub";
+
+// ============================================================================
+// Types
+// ============================================================================
+
+export interface ToolInfo {
+  name: DetectedType;
+  displayName: string;
+  description: string;
+  category: "agent" | "tool";
+  installCommand?: string;
+  installUrl?: string;
+  docsUrl?: string;
+}
+
+export interface ReadinessStatus {
+  ready: boolean;
+  agents: DetectedCLI[];
+  tools: DetectedCLI[];
+  summary: {
+    agentsAvailable: number;
+    agentsTotal: number;
+    toolsAvailable: number;
+    toolsTotal: number;
+    authIssues: string[];
+    missingRequired: string[];
+  };
+  recommendations: string[];
+  detectedAt: string;
+  durationMs: number;
+}
+
+export type InstallMode = "interactive" | "easy";
+
+export interface InstallRequest {
+  tool: DetectedType;
+  mode: InstallMode;
+  verify: boolean;
+}
+
+export type InstallStatus =
+  | "pending"
+  | "downloading"
+  | "installing"
+  | "verifying"
+  | "completed"
+  | "failed";
+
+export interface InstallProgress {
+  tool: string;
+  status: InstallStatus;
+  progress: number;
+  message: string;
+  timestamp: string;
+}
+
+export interface InstallResult {
+  tool: string;
+  success: boolean;
+  version?: string;
+  path?: string;
+  error?: string;
+  durationMs: number;
+}
+
